const data = $input.first().json;
const sessionKey = `order_${data.sessionId}`;
let existingOrder = [];
try {
  const stored = $vars[sessionKey];
  if (stored) existingOrder = JSON.parse(stored);
} catch(e) {}

const orderSummary = existingOrder.length
  ? 'Pedido actual:\n' + existingOrder.map(i => `- ${i.quantity}x ${i.name} S/. ${i.price}`).join('\n')
  : 'Pedido actual: vacio (el cliente aun no ha pedido nada)';

const orderPrompt = `${data.systemPrompt}\n\nMODO PEDIDO ACTIVO\n${orderSummary}\n\nTu tarea: ayudar al cliente a completar su pedido.\n- Si el cliente agrega algo, confirma el item y pregunta Algo mas?\n- Si el cliente dice 'eso es todo' o 'confirmar' o 'listo': muestra resumen completo con total en S/. y pide confirmacion final.\n- Si el cliente confirma el resumen: termina tu respuesta con la linea exacta: ORDER_CONFIRMED\n- Si el cliente quiere cambiar algo: actualiza mentalmente el pedido.`;

return [{ json: { ...data, orderPrompt, existingOrder, sessionKey } }];

const responseText = $input.first().json.content?.[0]?.text ?? '';
const confirmed = responseText.includes('ORDER_CONFIRMED');
const cleanText = responseText.replace('ORDER_CONFIRMED', '').trim();
const prev = $('Build Order Prompt').first().json;
return [{ json: { ...prev, botResponse: cleanText, orderConfirmed: confirmed } }];

const pedidoId = $input.first().json.id ?? 'nuevo';
const prev = $('Check Order Confirmed').first().json;
return [{ json: { ...prev, botResponse: `Pedido #${String(pedidoId).slice(0,8)} confirmado! Tiempo estimado: ~20 min` } }];
